// File containing the definitions of various helper math functions// that will be used in computations#include "math.hpp"#include <cmath>#include <vector>namespace {double SignedDoubleArea(const std::vector<Vertex>& polygon) {    if (polygon.size() < 3) {        return 0.0;    }    double area = 0.0;    for (std::size_t i = 0; i < polygon.size(); ++i) {        area += Determinant(polygon[i], polygon[(i + 1) % polygon.size()]);    }    return area;}double Cross(Vertex origin, Vertex lhs, Vertex rhs) {    return CrossProduct(lhs - origin, rhs - origin);}bool NearlyEqual(double lhs, double rhs, double epsilon = EPSILON) {    return std::abs(lhs - rhs) <= epsilon;}bool SamePoint(const Vertex& lhs, const Vertex& rhs, double epsilon = EPSILON) {    return NearlyEqual(lhs.x, rhs.x, epsilon) && NearlyEqual(lhs.y, rhs.y, epsilon);}bool IsFinitePoint(const Vertex& point) {    return std::isfinite(point.x) && std::isfinite(point.y);}std::optional<Vertex> InfiniteLineIntersection(    const Vertex& p1,    const Vertex& p2,    const Vertex& q1,    const Vertex& q2) {    const Vertex r = p2 - p1;    const Vertex s = q2 - q1;    const double denominator = CrossProduct(r, s);    if (std::abs(denominator) <= EPSILON) {        return std::nullopt;    }    const double t = CrossProduct(q1 - p1, s) / denominator;    return p1 + (r * t);}std::vector<Vertex> NormalizedCCWPolygon(std::vector<Vertex> polygon) {    if (SignedDoubleArea(polygon) < 0.0) {        std::reverse(polygon.begin(), polygon.end());    }    return polygon;}bool InsideHalfPlane(const Vertex& edge_start, const Vertex& edge_end, const Vertex& point) {    return Cross(edge_start, edge_end, point) >= -EPSILON;}std::vector<Vertex> ConvexClip(std::vector<Vertex> subject, const std::vector<Vertex>& clip_polygon) {    subject = NormalizedCCWPolygon(std::move(subject));    const std::vector<Vertex> clip = NormalizedCCWPolygon(clip_polygon);    for (std::size_t i = 0; i < clip.size() && !subject.empty(); ++i) {        const Vertex& clip_start = clip[i];        const Vertex& clip_end = clip[(i + 1) % clip.size()];        std::vector<Vertex> output;        for (std::size_t j = 0; j < subject.size(); ++j) {            const Vertex& current = subject[j];            const Vertex& previous = subject[(j + subject.size() - 1) % subject.size()];            const bool current_inside = InsideHalfPlane(clip_start, clip_end, current);            const bool previous_inside = InsideHalfPlane(clip_start, clip_end, previous);            if (current_inside) {                if (!previous_inside) {                    const std::optional<Vertex> intersection =                        InfiniteLineIntersection(previous, current, clip_start, clip_end);                    if (intersection.has_value()) {                        output.push_back(*intersection);                    }                }                output.push_back(current);            } else if (previous_inside) {                const std::optional<Vertex> intersection =                    InfiniteLineIntersection(previous, current, clip_start, clip_end);                if (intersection.has_value()) {                    output.push_back(*intersection);                }            }        }        subject = std::move(output);    }    std::vector<Vertex> deduplicated;    for (const Vertex& point : subject) {        if (deduplicated.empty() || !SamePoint(point, deduplicated.back())) {            deduplicated.push_back(point);        }    }    if (deduplicated.size() >= 2 && SamePoint(deduplicated.front(), deduplicated.back())) {        deduplicated.pop_back();    }    return deduplicated;}double TriangleSymmetricDifferenceArea(    const Vertex& a1,    const Vertex& b1,    const Vertex& c1,    const Vertex& a2,    const Vertex& b2,    const Vertex& c2) {    const std::vector<Vertex> triangle_one{a1, b1, c1};    const std::vector<Vertex> triangle_two{a2, b2, c2};    const double area_one = std::abs(SignedDoubleArea(triangle_one)) * 0.5;    const double area_two = std::abs(SignedDoubleArea(triangle_two)) * 0.5;    const std::vector<Vertex> intersection = ConvexClip(triangle_one, triangle_two);    const double intersection_area =        intersection.size() >= 3 ? std::abs(SignedDoubleArea(intersection)) * 0.5 : 0.0;    return area_one + area_two - (2.0 * intersection_area);}bool IsStrictlyBetter(const APSCCollapseResult& lhs, const APSCCollapseResult& rhs) {    if (!NearlyEqual(lhs.local_displacement, rhs.local_displacement)) {        return lhs.local_displacement < rhs.local_displacement;    }    return static_cast<int>(lhs.side) < static_cast<int>(rhs.side);}} // namespace// LINKS// https://www.geeksforgeeks.org/cpp/line-intersection-in-cpp/// https://stackoverflow.com/questions/20677795/how-do-i-compute-the-intersection-point-of-two-lines// https://www.101computing.net/the-shoelace-algorithm/// -- HELPERS --double Determinant(Vertex A, Vertex B) {    return A.x * B.y - A.y * B.x;}double Determinant(Line line) {    return line.a->x * line.b->y - line.a->y * line.b->x;}// -- LINE RELATED OPERATIONS -- // dot product// A.x * B.x + A.y * B.ydouble DotProduct(Vector A, Vector B) {    return A.x * B.x + A.y * B.y;}// cross product// x = A.y * 0   - 0 * B.y = 0// y = 0 * B.x   - A.x * 0 = 0// z = A.x * B.y - A.y * B.x  -> this is the only surviving termdouble CrossProduct(Vector A, Vector B) {    return A.x * B.y - A.y * B.x;}// line intersection - should not return anything proper// if lines are parallel. therefore it is encased in an optional std::optional<Vertex> LineIntersection(Line A, Line B) {     // guards in case the vertices are null for whatever     // reason     if (A.a == nullptr || A.b == nullptr || B.a == nullptr || B.b == nullptr) return std::nullopt;    return InfiniteLineIntersection(*A.a, *A.b, *B.a, *B.b);}// -- POLYGON RELATED OPERATIONS -- // signed area - shoelace method, sign tells orientation// IMPORTANT: VERTICES MUST BE ENTERED IN ANTICLOCKWISE ORDERdouble SignedArea(std::vector<Vertex> poly, bool reverse) {    std::vector<Vertex> polygon = poly;    if (reverse) {        std::reverse(polygon.begin(), polygon.end());    }    return SignedDoubleArea(polygon) * 0.5;}// Signed area = (AB x AC) / 2double TriangleArea(Vertex A, Vertex B, Vertex C) {    return CrossProduct(B - A, C - A) / 2.0;}// topology checks// should be used everywhere else intopology checks// DoLinesIntersect  -> only fails if lines are PARALLEL (direction vectors same)// SegmentsIntersect -> fails if parallel OR if intersection point is outside both segments// lines - infinite line, segment - has end pointsbool SegmentsIntersect(Line A, Line B) {    if (A.a == nullptr || A.b == nullptr || B.a == nullptr || B.b == nullptr) return false;    int d1 = Orientation(*B.a, *B.b, *A.a);    int d2 = Orientation(*B.a, *B.b, *A.b);    int d3 = Orientation(*A.a, *A.b, *B.a);    int d4 = Orientation(*A.a, *A.b, *B.b);    // general case    if (d1 != d2 && d3 != d4) return true;    // collinear edge cases    if (d1 == 0 && PointOnSegment(*A.a, B)) return true;    if (d2 == 0 && PointOnSegment(*A.b, B)) return true;    if (d3 == 0 && PointOnSegment(*B.a, A)) return true;    if (d4 == 0 && PointOnSegment(*B.b, A)) return true;    return false;}bool IsCollinear(Vertex A, Vertex B, Vertex C) {    return Orientation(A, B, C) == 0;}// edge case in intersection checksbool PointOnSegment(Vertex P, Line seg) {    // P must be collinear with segment AND within the bounding box    if (!IsCollinear(*seg.a, P, *seg.b)) return false;    return std::min(seg.a->x, seg.b->x) <= P.x && P.x <= std::max(seg.a->x, seg.b->x) &&    std::min(seg.a->y, seg.b->y) <= P.y && P.y <= std::max(seg.a->y, seg.b->y);}// orientation check// returns -1, 0, 1 for clockwise, collinear, counterclockwise// can be used in winding checks and intersection logicint Orientation(Vertex A, Vertex B, Vertex C) {    double cross = CrossProduct(        {B.x - A.x, B.y - A.y},        {C.x - A.x, C.y - A.y}    );    if (std::abs(cross) < EPSILON) return 0;  // collinear    return (cross > 0) ? 1 : -1;              // 1=CCW, -1=CW}// APSC local geometry corestd::optional<Vertex> ComputeAreaPreservingPointE(    const Vertex& A,    const Vertex& B,    const Vertex& C,    const Vertex& D,    APSCPlacementSide side) {    const double signed_double_local_area = SignedDoubleArea({A, B, C, D});    const Vertex ad = D - A;    Vertex direction;    Vertex anchor;    if (side == APSCPlacementSide::OnAB) {        direction = B - A;        anchor = A;    } else {        direction = C - D;        anchor = D;    }    const double denominator = CrossProduct(direction, ad);    if (std::abs(denominator) <= EPSILON) {        return std::nullopt;    }    const double t = signed_double_local_area / denominator;    const Vertex candidate = anchor + (direction * t);    if (!IsFinitePoint(candidate) || SamePoint(candidate, A) || SamePoint(candidate, D)) {        return std::nullopt;    }    return candidate;}double ComputeLocalArealDisplacement(    const Vertex& A,    const Vertex& B,    const Vertex& C,    const Vertex& D,    const Vertex& E,    APSCPlacementSide side) {    if (side == APSCPlacementSide::OnAB) {        return TriangleSymmetricDifferenceArea(B, C, D, B, E, D);    }    return TriangleSymmetricDifferenceArea(A, B, C, A, E, C);}std::optional<APSCCollapseResult> ComputeBestAPSCReplacement(    const Vertex& A,    const Vertex& B,    const Vertex& C,    const Vertex& D) {    std::optional<APSCCollapseResult> best;    for (APSCPlacementSide side : {APSCPlacementSide::OnAB, APSCPlacementSide::OnCD}) {        const std::optional<Vertex> point = ComputeAreaPreservingPointE(A, B, C, D, side);        if (!point.has_value()) {            continue;        }        APSCCollapseResult candidate{            .point = *point,            .local_displacement = ComputeLocalArealDisplacement(A, B, C, D, *point, side),            .side = side,        };        if (!best.has_value() || IsStrictlyBetter(candidate, *best)) {            best = candidate;        }    }    return best;}const char* APSCPlacementSideName(APSCPlacementSide side) {    switch (side) {        case APSCPlacementSide::OnAB:            return "AB";        case APSCPlacementSide::OnCD:            return "CD";        default:            return "unknown";    }}// distance functions// for checking how close E lands to other ringsdouble DistancePointToSegment(Vertex P, Line seg) {    return 0.0;}double DistancePointToPoint(Vertex A, Vertex B) {    return 0.0;}// point containment - critical for hole checking// ray casting algorithm// checks if E lands inside a hole which would be topologically invalidbool PointInRing(Vertex P, std::vector<Vertex> ring) {    return false;}// winding number - related to above// more robust than ray casting for edge casesint WindingNumber(Vertex P, std::vector<Vertex> ring) {    return false;}// just SignedArea < 0 basically// but having it named explicitly makes the topology // validation code much more readablebool IsRingClockwise(std::vector<Vertex> ring) {    return false;}